-- =============================================================================
-- BILLS MODULE — SQLC QUERIES
-- File: db/queries/bills.sql
--
-- Type-safe Go for the bills + bill_attachments tables defined in
-- db/schema/bills_schema.sql. Generated by a DEDICATED sqlc block (see sqlc.yaml)
-- into package `bills` at db/bills — separate from the other domain packages so
-- types don't bleed across modules.
--
-- Annotation / parameter syntax is identical to the other query files:
--   -- name: FuncName :one|:many|:exec
--   $1, $2 ...  positional params, typed from the schema columns.
--
-- Every query is ORGANISATION-SCOPED (multi-tenancy) and, on the header,
-- SOFT-DELETE-AWARE (deleted_at IS NULL). organisation_id / created_by_user_id
-- come from the authenticated token in the (future) service layer, never from the
-- request body.
--
-- The header's STATUS and PAID value are mutated by their own dedicated queries
-- (UpdateBillStatus / UpdateBillPaidValue), NOT by UpdateBill — so a field edit
-- can't accidentally clobber the lifecycle or the payment, mirroring how invoices
-- and the expenses module keep status transitions separate from field edits.
-- =============================================================================


-- =============================================================================
-- BILL  (the record — header + single spending line)
-- =============================================================================

-- -----------------------------------------------------------------------------
-- CreateBill  (the "setter")
-- Inserts a bill and returns the full row via RETURNING * (so the caller gets the
-- generated id, defaults and the computed due_value_minor without a second
-- round-trip). The single spending line is flat on the row: category_id +
-- amounts_include_vat + vat_rate_bps + the net/sales_tax/total the service
-- computed. paid_value_minor defaults to 0 and status to 'DRAFT', so neither is
-- supplied here (they have their own update queries).
-- -----------------------------------------------------------------------------
-- name: CreateBill :one
INSERT INTO bills (
    organisation_id,
    created_by_user_id,
    contact_id,
    reference,
    dated_on,
    due_on,
    currency,
    comments,
    is_hire_purchase,
    category_id,
    amounts_include_vat,
    vat_rate_bps,
    net_value_minor,
    sales_tax_value_minor,
    total_value_minor,
    project_id
) VALUES (
    $1,   -- organisation_id       UUID (tenant that owns the bill)
    $2,   -- created_by_user_id    UUID (audit)
    $3,   -- contact_id            UUID (the supplier)
    $4,   -- reference             VARCHAR (supplier's invoice number)
    $5,   -- dated_on              DATE ("Bill Date")
    $6,   -- due_on                DATE ("Due On", nullable)
    $7,   -- currency              CHAR(3) e.g. 'GBP'
    $8,   -- comments              TEXT (nullable)
    $9,   -- is_hire_purchase      BOOLEAN
    $10,  -- category_id           UUID (CoA spending account)
    $11,  -- amounts_include_vat   BOOLEAN (the Incl/Excl-VAT radio)
    $12,  -- vat_rate_bps          INTEGER (resolved VAT rate, basis points)
    $13,  -- net_value_minor       BIGINT (ex-VAT, pence)
    $14,  -- sales_tax_value_minor BIGINT (VAT, pence)
    $15,  -- total_value_minor     BIGINT (gross, pence)
    $16   -- project_id            UUID (nullable "Link to Project")
)
RETURNING *;


-- -----------------------------------------------------------------------------
-- GetBill  (the "getter")
-- Fetch a single bill by id, scoped to the organisation. We ALWAYS scope by
-- organisation_id — never fetch by id alone — so one tenant can't read another's
-- bill if an id leaks. deleted_at IS NULL hides soft-deleted rows.
-- -----------------------------------------------------------------------------
-- name: GetBill :one
SELECT * FROM bills
WHERE id              = $1   -- bill UUID
  AND organisation_id = $2   -- tenant scope — never skip this
  AND deleted_at IS NULL;    -- soft delete filter


-- -----------------------------------------------------------------------------
-- ListBills  (the "list")
-- All live bills for an organisation, newest first, for the bills list page.
-- -----------------------------------------------------------------------------
-- name: ListBills :many
SELECT * FROM bills
WHERE organisation_id = $1
  AND deleted_at IS NULL
ORDER BY dated_on DESC, created_at DESC;


-- -----------------------------------------------------------------------------
-- ListBillsByContact
-- The live bills owed to one supplier (e.g. the contact detail page). Backed by
-- idx_bills_org_contact.
-- -----------------------------------------------------------------------------
-- name: ListBillsByContact :many
SELECT * FROM bills
WHERE organisation_id = $1
  AND contact_id      = $2
  AND deleted_at IS NULL
ORDER BY dated_on DESC, created_at DESC;


-- -----------------------------------------------------------------------------
-- UpdateBill  (the "update" — editable header + single-line body)
-- Full update of the caller-editable fields (PUT semantics). Deliberately does
-- NOT touch status or paid_value_minor — those have their own queries — nor
-- organisation_id / created_by_user_id. net/sales_tax/total ARE updated here
-- because they are recomputed by the service from the (edited) single line on
-- every save. updated_at is set explicitly in addition to the trigger
-- (belt-and-suspenders). Whether a bill is editable in its current status is a
-- service-layer guard.
-- -----------------------------------------------------------------------------
-- name: UpdateBill :one
UPDATE bills SET
    contact_id            = $3,
    reference             = $4,
    dated_on              = $5,
    due_on                = $6,
    currency              = $7,
    comments              = $8,
    is_hire_purchase      = $9,
    category_id           = $10,
    amounts_include_vat   = $11,
    vat_rate_bps          = $12,
    net_value_minor       = $13,
    sales_tax_value_minor = $14,
    total_value_minor     = $15,
    project_id            = $16,
    updated_at            = now()
WHERE id              = $1   -- bill UUID
  AND organisation_id = $2   -- tenant scope
  AND deleted_at IS NULL     -- can't update a deleted bill
RETURNING *;


-- -----------------------------------------------------------------------------
-- UpdateBillStatus
-- Moves the stored lifecycle (DRAFT|OPEN|WRITTEN_OFF). A single query suffices
-- because the minimal header has no per-transition timestamp columns to set
-- (unlike the expenses approval machine). Legal-transition checking is a
-- service guard; the DB CHECK only constrains the value set.
-- -----------------------------------------------------------------------------
-- name: UpdateBillStatus :one
UPDATE bills SET
    status     = $3,
    updated_at = now()
WHERE id              = $1
  AND organisation_id = $2
  AND deleted_at IS NULL
RETURNING *;


-- -----------------------------------------------------------------------------
-- UpdateBillPaidValue
-- Sets the amount settled against the bill. Anticipates the payments /
-- reconciliation path (deferred — see BACKLOG); paid_value_minor drives the
-- DERIVED Paid/Overpaid/Overdue display status, and due_value_minor recomputes
-- from it automatically.
-- -----------------------------------------------------------------------------
-- name: UpdateBillPaidValue :one
UPDATE bills SET
    paid_value_minor = $3,
    updated_at       = now()
WHERE id              = $1
  AND organisation_id = $2
  AND deleted_at IS NULL
RETURNING *;


-- -----------------------------------------------------------------------------
-- SoftDeleteBill  (the "delete")
-- Sets deleted_at to mark the bill deleted (it stays in the DB for audit and so
-- payments/history that reference it don't dangle). Mirrors SoftDeleteInvoice.
-- :exec returns only an error. Idempotent — deleting an already-deleted bill
-- matches no live row and is a no-op. Whether the bill's status ALLOWS deletion
-- (e.g. DRAFT only) is a service-layer guard.
-- -----------------------------------------------------------------------------
-- name: SoftDeleteBill :exec
UPDATE bills SET
    deleted_at = now(),
    updated_at = now()
WHERE id              = $1
  AND organisation_id = $2
  AND deleted_at IS NULL;


-- -----------------------------------------------------------------------------
-- ContactHasBills
-- "Is this contact referenced by any live bill?" — the cross-domain check the
-- contacts module's delete guard needs (a soft-deleted contact must not strand
-- bills). Mirrors projects.ContactHasProjects / invoices.ContactHasInvoices; the
-- contacts service will inject the bills querier and OR this into its in-use
-- check (wiring deferred to the service increment — this is the datalayer half).
-- -----------------------------------------------------------------------------
-- name: ContactHasBills :one
SELECT EXISTS (
    SELECT 1 FROM bills
    WHERE contact_id      = $1   -- contact UUID
      AND organisation_id = $2   -- tenant scope — never skip this
      AND deleted_at IS NULL
) AS has_bills;


-- -----------------------------------------------------------------------------
-- ListBillCategories
-- The "Spending Category" picker. The bill's category_id is a CoA (categories)
-- account, but a bill may only post to a SPENDING account — so we return just the
-- subset the expense form offers: cost of sales, admin expenses and capital
-- assets. Income / balance-sheet / system-managed accounts are excluded. Selects
-- default_vat so the service can resolve the form's "Auto" VAT rate from the
-- chosen category. Org-scoped, active rows only.
-- (The exact account_type set is intended to match what the expense form lists;
--  revisit if/when expense_categories and categories are unified — see BACKLOG.)
-- -----------------------------------------------------------------------------
-- name: ListBillCategories :many
SELECT id, nominal_code, name, account_type, api_group, default_vat
FROM categories
WHERE organisation_id = $1
  AND is_active
  AND is_system_managed = FALSE
  AND account_type IN ('COST_OF_SALES','ADMIN_EXPENSE','CAPITAL_ASSET')
ORDER BY account_type, nominal_code;


-- =============================================================================
-- BILL ATTACHMENTS
-- Clone of the expense_attachments query set, scoped to bills. The bytes live in
-- GCS; these rows are the metadata. The GCS upload / OCR WIRING is deferred — but
-- the queries exist so the future bill attachment + Smart-Capture service can use
-- them unchanged.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- CreateBillAttachment
-- Records metadata for an uploaded file. The actual file has already been written
-- to GCS by the time this is called. storage_path is the GCS object key — never a
-- signed URL (those are generated on demand, not stored).
-- -----------------------------------------------------------------------------
-- name: CreateBillAttachment :one
INSERT INTO bill_attachments (
    bill_id,
    organisation_id,
    file_name,
    content_type,
    file_size_bytes,
    storage_path,
    storage_bucket,
    description,
    is_primary,
    uploaded_by_user_id,
    content_hash
) VALUES (
    $1,   -- bill_id              UUID
    $2,   -- organisation_id      UUID
    $3,   -- file_name            VARCHAR e.g. 'supplier_invoice.pdf'
    $4,   -- content_type         VARCHAR e.g. 'application/pdf'
    $5,   -- file_size_bytes      INTEGER
    $6,   -- storage_path         TEXT e.g. 'orgs/abc123/bills/xyz/invoice.pdf'
    $7,   -- storage_bucket       VARCHAR e.g. 'myapp-bill-documents-prod'
    $8,   -- description          TEXT (nullable — user label for this file)
    $9,   -- is_primary           BOOLEAN
    $10,  -- uploaded_by_user_id  UUID
    $11   -- content_hash         VARCHAR (nullable — hex SHA-256 of the file bytes)
)
RETURNING *;


-- -----------------------------------------------------------------------------
-- ListBillAttachments
-- All attachments for one bill, primary file first. The UI shows them in this
-- order (is_primary DESC: TRUE sorts before FALSE, so primary comes first).
-- -----------------------------------------------------------------------------
-- name: ListBillAttachments :many
SELECT * FROM bill_attachments
WHERE bill_id = $1
ORDER BY is_primary DESC, created_at ASC;


-- -----------------------------------------------------------------------------
-- GetBillAttachment
-- Single attachment by id — used when generating a signed download URL. Scoped by
-- organisation_id to prevent cross-tenant access.
-- -----------------------------------------------------------------------------
-- name: GetBillAttachment :one
SELECT * FROM bill_attachments
WHERE id              = $1
  AND organisation_id = $2;


-- -----------------------------------------------------------------------------
-- FindDuplicateBillReceipt
-- Content-level dedupe: is there already a NON-DELETED bill in this org whose
-- attachment has the identical content hash? Returns that bill's id if so (the
-- caller then skips re-capturing the same file). A bill has no claimant, so —
-- unlike the expense version — this is scoped by organisation only. Hits
-- idx_bill_attachments_content_hash.
-- -----------------------------------------------------------------------------
-- name: FindDuplicateBillReceipt :one
SELECT a.bill_id
FROM bill_attachments a
JOIN bills b ON b.id = a.bill_id
WHERE a.organisation_id = $1
  AND a.content_hash    = $2
  AND b.deleted_at IS NULL
LIMIT 1;


-- -----------------------------------------------------------------------------
-- UpdateBillAttachmentOCRStatus
-- Records a TERMINAL OCR result (COMPLETE / FAILED / SKIPPED) on an attachment.
-- ocr_extracted_data is JSONB — in Go a []byte the service marshals from its
-- extraction result. ocr_processed_at is stamped now() because the attachment has
-- reached a terminal OCR state. Org-scoped as defence in depth. For the
-- PENDING→PROCESSING transition use MarkBillAttachmentOCRProcessing instead, which
-- deliberately does NOT stamp ocr_processed_at.
-- -----------------------------------------------------------------------------
-- name: UpdateBillAttachmentOCRStatus :one
UPDATE bill_attachments SET
    ocr_status         = $3,   -- 'COMPLETE'|'FAILED'|'SKIPPED'
    ocr_raw_text       = $4,   -- full text from OCR engine (nullable)
    ocr_extracted_data = $5,   -- JSONB structured fields (nullable)
    ocr_processed_at   = now(),
    updated_at         = now()
WHERE id              = $1
  AND organisation_id = $2     -- tenant scope — never skip this
RETURNING *;


-- -----------------------------------------------------------------------------
-- MarkBillAttachmentOCRProcessing
-- Flips an attachment from PENDING to PROCESSING when the OCR worker picks it up.
-- Deliberately separate from UpdateBillAttachmentOCRStatus: a non-terminal
-- transition, so it does NOT set ocr_processed_at. Org-scoped like every write.
-- -----------------------------------------------------------------------------
-- name: MarkBillAttachmentOCRProcessing :exec
UPDATE bill_attachments SET
    ocr_status = 'PROCESSING',
    updated_at = now()
WHERE id              = $1
  AND organisation_id = $2;


-- -----------------------------------------------------------------------------
-- DeleteBillAttachment
-- Hard delete — attachments can be genuinely removed (they're supporting
-- documents, not financial records themselves). The file in GCS must be deleted
-- separately by the application layer after this succeeds. :exec returns only an
-- error.
-- -----------------------------------------------------------------------------
-- name: DeleteBillAttachment :exec
DELETE FROM bill_attachments
WHERE id              = $1
  AND organisation_id = $2;


-- -----------------------------------------------------------------------------
-- CountBillAttachments
-- How many files a bill already has. The service calls this when a new file is
-- uploaded: if the count is 0, this upload is the FIRST and becomes the primary
-- (default) attachment. Scoped by bill_id only — the caller has already been
-- authorised against the parent bill's organisation.
-- -----------------------------------------------------------------------------
-- name: CountBillAttachments :one
SELECT count(*) FROM bill_attachments
WHERE bill_id = $1;


-- -----------------------------------------------------------------------------
-- UnsetBillPrimary
-- Clears the primary flag on every attachment of a bill. Run inside a transaction
-- immediately BEFORE SetBillAttachmentPrimary so exactly one row ends up flagged
-- primary. organisation_id keeps the update tenant-scoped.
-- -----------------------------------------------------------------------------
-- name: UnsetBillPrimary :exec
UPDATE bill_attachments SET
    is_primary = FALSE,
    updated_at = now()
WHERE bill_id         = $1
  AND organisation_id = $2
  AND is_primary      = TRUE;


-- -----------------------------------------------------------------------------
-- SetBillAttachmentPrimary
-- Marks a single attachment as the primary one for its bill. Pair it with
-- UnsetBillPrimary inside one transaction so the "exactly one primary" invariant
-- holds. organisation_id prevents cross-tenant writes.
-- -----------------------------------------------------------------------------
-- name: SetBillAttachmentPrimary :exec
UPDATE bill_attachments SET
    is_primary = TRUE,
    updated_at = now()
WHERE id              = $1
  AND organisation_id = $2;
